import React, { useState, useEffect } from 'react';
import { 
  BriefcaseIcon,
  CalendarIcon,
  MapPinIcon,
  BuildingOfficeIcon
} from '@heroicons/react/24/outline';

interface WorkExperienceItem {
  id: number;
  position: string;
  company: string;
  location: string;
  startDate: string;
  endDate?: string;
  isCurrent: boolean;
  description: string;
  technologies: string;
  achievements: string;
}

// Временные статичные данные для демонстрации
const mockWorkExperience: WorkExperienceItem[] = [
  {
    id: 1,
    position: "Инженер-программист",
    company: "ООО «Проект 24»",
    location: "Казань, Россия",
    startDate: "2022-02-01",
    endDate: "",
    isCurrent: true,
    description: "Разработка промышленных систем автоматизации, программирование микроконтроллеров STM32 и ESP32, создание Android приложений для промышленного оборудования.",
    technologies: "STM32, ESP32, Android Java, Bluetooth, Modbus, Altium Designer",
    achievements: "Создание USB Bluetooth Mass Storage для швейных машин Janome; Разработка системы контроля утечки газа; Проектирование LED контроллеров с Modbus"
  },
  {
    id: 2,
    position: "Java-программист",
    company: "Maxima OOO",
    location: "Казань, Россия",
    startDate: "2022-11-01",
    endDate: "2023-06-30",
    isCurrent: false,
    description: "Разработка корпоративных приложений на Java Spring Boot, создание REST API, работа с базами данных PostgreSQL и MySQL.",
    technologies: "Java Spring Boot, PostgreSQL, MySQL, REST API, Docker",
    achievements: "Разработка системы управления персоналом; Оптимизация производительности баз данных; Внедрение микросервисной архитектуры"
  },
  {
    id: 3,
    position: "Инженер-программист",
    company: "ООО \"Челны свет\"",
    location: "Набережные Челны, Россия",
    startDate: "2021-03-01",
    endDate: "2021-12-31",
    isCurrent: false,
    description: "Программирование промышленных ПЛК Omron, разработка SCADA систем, проектирование систем управления освещением.",
    technologies: "Omron PLC, SCADA, CodeSys, Modbus, RS-485",
    achievements: "Автоматизация системы управления уличным освещением; Создание диспетчерского центра; Снижение энергопотребления на 30%"
  },
  {
    id: 4,
    position: "Инженер программист микроконтроллеров",
    company: "ООО \"Водий нефтегазовик энергия\"",
    location: "Туркменистан",
    startDate: "2017-08-01",
    endDate: "2018-04-30",
    isCurrent: false,
    description: "Разработка систем контроля и управления для нефтегазовой промышленности, программирование микроконтроллеров для датчиков давления и температуры.",
    technologies: "STM32, Texas Instruments Tiva, 4-20mA, GSM, Датчики давления",
    achievements: "Система мониторинга нефтепроводов; Беспроводная передача данных; Повышение надежности контроля"
  },
  {
    id: 5,
    position: "Инженер-программист АСУ ТП",
    company: "ХО \"Восполнение\"",
    location: "Туркменистан",
    startDate: "2015-04-01",
    endDate: "2017-07-31",
    isCurrent: false,
    description: "Проектирование и внедрение автоматизированных систем управления технологическими процессами, программирование ПЛК различных производителей.",
    technologies: "ОВЕН ПЛК, СПК107, JUMO mTRON T, Modbus, SCADA",
    achievements: "Система управления инкубатором; Климат-контроль с ОВЕН PLC160; Автоматизация 15+ технологических процессов"
  }
];

const Experience: React.FC = () => {
  const [workExperience, setWorkExperience] = useState<WorkExperienceItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchWorkExperience = async () => {
      try {
        const response = await fetch('http://localhost:8080/api/work-experience');
        if (!response.ok) {
          throw new Error('Failed to fetch work experience');
        }
        const data = await response.json();
        setWorkExperience(data);
        setLoading(false);
        setError(null);
      } catch (err) {
        console.warn('API не доступен, используем статичные данные:', err);
        // Используем статичные данные если API недоступен
        setWorkExperience(mockWorkExperience);
        setLoading(false);
        setError(null);
      }
    };

    fetchWorkExperience();
  }, []);

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('ru-RU', { 
      year: 'numeric', 
      month: 'long' 
    });
  };

  const calculateDuration = (startDate: string, endDate?: string) => {
    const start = new Date(startDate);
    const end = endDate ? new Date(endDate) : new Date();
    
    const months = (end.getFullYear() - start.getFullYear()) * 12 + 
                   (end.getMonth() - start.getMonth());
    
    const years = Math.floor(months / 12);
    const remainingMonths = months % 12;
    
    if (years === 0) {
      return `${remainingMonths} мес.`;
    } else if (remainingMonths === 0) {
      return `${years} ${years === 1 ? 'год' : years < 5 ? 'года' : 'лет'}`;
    } else {
      return `${years} ${years === 1 ? 'год' : years < 5 ? 'года' : 'лет'} ${remainingMonths} мес.`;
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-400 mx-auto"></div>
          <p className="text-gray-300 mt-4">Загрузка опыта работы...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 flex items-center justify-center">
        <div className="text-center">
          <p className="text-red-400 text-lg">{error}</p>
          <button 
            onClick={() => window.location.reload()} 
            className="mt-4 px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
          >
            Попробовать снова
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-4xl mx-auto">
        {/* Заголовок */}
        <div className="text-center mb-12">
          <h1 className="text-4xl font-bold text-white mb-4">
            <span className="bg-gradient-to-r from-blue-400 to-emerald-400 bg-clip-text text-transparent">
              Опыт работы
            </span>
          </h1>
          <p className="text-xl text-gray-300">
            25+ лет в области программирования микроконтроллеров и промышленной автоматизации
          </p>
        </div>

        {/* Timeline */}
        <div className="relative">
          {/* Вертикальная линия */}
          <div className="absolute left-8 top-0 bottom-0 w-0.5 bg-gradient-to-b from-blue-400 via-emerald-400 to-purple-400"></div>
          
          {workExperience.map((job, index) => (
            <div key={job.id} className="relative mb-12">
              {/* Точка на timeline */}
              <div className="absolute left-6 w-4 h-4 bg-gradient-to-r from-blue-400 to-emerald-400 rounded-full border-4 border-slate-900"></div>
              
              {/* Карточка работы */}
              <div className="ml-16 bg-gradient-to-br from-slate-800 to-slate-700 rounded-xl p-6 shadow-xl">
                {/* Заголовок */}
                <div className="flex flex-wrap items-start justify-between mb-4">
                  <div className="flex-1 min-w-0">
                    <h3 className="text-xl font-semibold text-white mb-2">
                      {job.position}
                    </h3>
                    <div className="flex items-center text-emerald-400 mb-2">
                      <BuildingOfficeIcon className="w-5 h-5 mr-2" />
                      <span className="font-medium">{job.company}</span>
                    </div>
                    {job.location && (
                      <div className="flex items-center text-gray-400 mb-2">
                        <MapPinIcon className="w-4 h-4 mr-2" />
                        <span>{job.location}</span>
                      </div>
                    )}
                  </div>
                  
                  {job.isCurrent && (
                    <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-emerald-100 text-emerald-800">
                      Текущая должность
                    </span>
                  )}
                </div>

                {/* Даты */}
                <div className="flex items-center text-blue-400 mb-4">
                  <CalendarIcon className="w-4 h-4 mr-2" />
                  <span>
                    {formatDate(job.startDate)} — {job.endDate ? formatDate(job.endDate) : 'настоящее время'}
                  </span>
                  <span className="mx-2">•</span>
                  <span className="text-gray-400">
                    {calculateDuration(job.startDate, job.endDate)}
                  </span>
                </div>

                {/* Описание */}
                <div className="mb-4">
                  <p className="text-gray-300 leading-relaxed">
                    {job.description}
                  </p>
                </div>

                {/* Технологии */}
                {job.technologies && (
                  <div className="mb-4">
                    <h4 className="text-sm font-semibold text-gray-400 mb-2">Технологии:</h4>
                    <div className="flex flex-wrap gap-2">
                      {job.technologies.split(',').map((tech, techIndex) => (
                        <span 
                          key={techIndex}
                          className="px-2 py-1 bg-slate-600/50 text-blue-300 text-xs rounded border border-slate-500"
                        >
                          {tech.trim()}
                        </span>
                      ))}
                    </div>
                  </div>
                )}

                {/* Достижения */}
                {job.achievements && (
                  <div>
                    <h4 className="text-sm font-semibold text-gray-400 mb-2">Основные достижения:</h4>
                    <ul className="text-gray-300 text-sm space-y-1">
                      {job.achievements.split(';').map((achievement, achIndex) => (
                        <li key={achIndex} className="flex items-start">
                          <span className="text-emerald-400 mr-2">•</span>
                          <span>{achievement.trim()}</span>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>

        {/* Итого */}
        <div className="text-center mt-16 p-8 bg-gradient-to-r from-slate-800 to-slate-700 rounded-xl">
          <BriefcaseIcon className="w-12 h-12 text-blue-400 mx-auto mb-4" />
          <h3 className="text-2xl font-bold text-white mb-2">
            Общий опыт работы: 25+ лет
          </h3>
          <p className="text-gray-300">
            От программирования на Turbo Pascal до современных технологий IoT и промышленной автоматизации
          </p>
        </div>

        {/* Призыв к действию */}
        <div className="text-center mt-16">
          <div className="bg-gradient-to-r from-blue-600 to-emerald-600 rounded-xl p-8">
            <h2 className="text-2xl font-bold text-white mb-4">
              Готов к новым вызовам
            </h2>
            <p className="text-blue-100 mb-6">
              25+ лет опыта в промышленном программировании и автоматизации. 
              Всегда открыт для интересных проектов и сотрудничества.
            </p>
            <div className="flex flex-col sm:flex-row gap-4 justify-center">
              <a
                href="mailto:timursultanw@yandex.ru"
                className="bg-white text-blue-600 px-8 py-3 rounded-lg font-semibold hover:bg-blue-50 transition-colors"
              >
                Связаться со мной
              </a>
              <a
                href="tel:+79272444051"
                className="border-2 border-white text-white px-8 py-3 rounded-lg font-semibold hover:bg-white hover:text-blue-600 transition-colors"
              >
                +7 927 244-40-51
              </a>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Experience;
